"""Unit tests for the rSkill README + manifest documentation validator.

Pins the publish-gate contract for ``tools/rskill_publisher.py``:

* A missing / too-short / sentinel-laden README blocks publishing.
* A manifest with the template's ``"Scaffold template generated by …"``
  description blocks publishing.
* A manifest with neither ``paper_url`` nor ``source_repo`` blocks publishing.
* A ``TEMPLATE_ORG`` / ``TEMPLATE_ID`` substring anywhere in the manifest
  blocks publishing.
* Every in-tree rSkill (sans the template scaffold itself) passes the
  validator — regression guard so a new gate doesn't quietly break a
  shipped skill.

No mocks: tests build real ``RSkillManifest`` instances from YAML
fixtures written to ``tmp_path`` and call the validator against real
files (CLAUDE.md §1.11). The in-tree regression test reads the actual
``rskills/*/README.md`` and ``rskills/*/rskill.yaml`` from the repo.
"""

from __future__ import annotations

import textwrap
from pathlib import Path

import pytest
from openral_cli._rskill_doc_validator import (
    DELEGATION_MARKER_NAME,
    PLACEHOLDER_MANIFEST_DESCRIPTION_MARKERS,
    DocValidationReport,
    format_report,
    validate_rskill_docs,
)
from openral_core.schemas import RSkillManifest

# ── Test fixtures ────────────────────────────────────────────────────────────

_VALID_MANIFEST_YAML = textwrap.dedent("""\
    name: test/rskill-doc-fixture
    version: "0.1.0"
    license: apache-2.0
    role: s1
    kind: vla
    model_family: smolvla
    embodiment_tags: [so100_follower]
    runtime: pytorch
    weights_uri: "hf://test/doc-fixture"
    chunk_size: 16
    latency_budget:
      per_chunk_ms: 100.0
    actuators_required:
      - kind: joint_position
        control_mode_semantics: {mode: absolute}
    processors:
      preprocessor_uri: "hf://test/doc-fixture/policy_preprocessor.json"
      postprocessor_uri: "hf://test/doc-fixture/policy_postprocessor.json"
    paper_url: "https://arxiv.org/abs/9999.99999"
    source_repo: "hf://test/doc-fixture"
    description: "Picks a cube from the tabletop on the SO-100 follower arm."
    actions:
      - pick
    objects:
      - cube
    scenes:
      - tabletop
""")

_GOOD_README = textwrap.dedent("""\
    # rskill-doc-fixture

    > **OpenRAL rSkill** — pick a cube on the SO-100 follower arm.
    > Real package, real README, fully filled in.

    ## Upstream model

    Wraps the upstream Apache-2.0 checkpoint. Paper: SmolVLA (arxiv:2506.01844).
    Trained on the LIBERO benchmark with ~1700 demonstrations.

    ## Supported robots

    | Robot | Embodiment tag | Status |
    | --- | --- | --- |
    | SO-100 follower | so100_follower | ✓ validated |

    ## Sensors required

    | Key | Modality | Resolution |
    | --- | --- | --- |
    | observation.images.camera1 | RGB | 224 × 224 |
    | observation.images.camera2 | RGB | 224 × 224 |

    ## Manifest summary

    See `rskill.yaml` for the full set of fields.

    ## License

    Apache-2.0, matching the wrapped upstream weights.
""")


def _write_skill_dir(
    base: Path,
    *,
    manifest_yaml: str = _VALID_MANIFEST_YAML,
    readme: str | None = _GOOD_README,
) -> tuple[Path, RSkillManifest]:
    """Create a real rSkill directory under ``base`` and return (dir, manifest).

    Args:
        base: The parent directory (typically a pytest ``tmp_path``).
        manifest_yaml: YAML body to write as ``rskill.yaml``.
        readme: README body to write, or ``None`` to skip the README.
    """
    skill_dir = base / "rskill-doc-fixture"
    skill_dir.mkdir(parents=True)
    (skill_dir / "rskill.yaml").write_text(manifest_yaml, encoding="utf-8")
    if readme is not None:
        (skill_dir / "README.md").write_text(readme, encoding="utf-8")
    manifest = RSkillManifest.from_yaml(str(skill_dir / "rskill.yaml"))
    return skill_dir, manifest


# ── Happy path ──────────────────────────────────────────────────────────────


def test_valid_rskill_passes(tmp_path: Path) -> None:
    """A real manifest + a fleshed-out README → no errors."""
    skill_dir, manifest = _write_skill_dir(tmp_path)
    report = validate_rskill_docs(skill_dir, manifest)
    assert report.is_valid, report.errors
    assert report.errors == []


def test_report_carries_manifest_name(tmp_path: Path) -> None:
    skill_dir, manifest = _write_skill_dir(tmp_path)
    report = validate_rskill_docs(skill_dir, manifest)
    assert report.manifest_name == "test/rskill-doc-fixture"
    assert report.skill_dir.endswith("rskill-doc-fixture")


# ── README failure modes ─────────────────────────────────────────────────────


def test_missing_readme_blocks_publish(tmp_path: Path) -> None:
    skill_dir, manifest = _write_skill_dir(tmp_path, readme=None)
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    fields = {i.field for i in report.errors}
    assert "readme" in fields


def test_short_readme_blocks_publish(tmp_path: Path) -> None:
    skill_dir, manifest = _write_skill_dir(tmp_path, readme="# tiny\n")
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    assert any(i.field == "readme.body" for i in report.errors)


def test_readme_missing_license_section_blocks_publish(tmp_path: Path) -> None:
    readme = _GOOD_README.replace("## License", "## Legalese-ish")
    # The substring "license" doesn't appear in any heading now; section fails.
    # Note: "license" might still appear in the body (it does), but the
    # validator scans headings only — that's the point.
    readme_clean = readme.replace("Apache-2.0, matching the wrapped upstream weights.", "")
    skill_dir, manifest = _write_skill_dir(tmp_path, readme=readme_clean)
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    license_errors = [i for i in report.errors if "license" in i.field.lower()]
    assert license_errors, f"expected a license section error, got {report.errors}"


def test_readme_missing_robots_section_blocks_publish(tmp_path: Path) -> None:
    readme = _GOOD_README.replace("## Supported robots", "## Compatibility")
    # "compatibility" doesn't match any of robot/embodiment/supported,
    # but "Supported robots" did. With it renamed, the section is missing.
    skill_dir, manifest = _write_skill_dir(tmp_path, readme=readme)
    report = validate_rskill_docs(skill_dir, manifest)
    # Note: "supported" is still in the substring list; we have to make sure
    # neither "robot" nor "embodiment" nor "supported" survives anywhere.
    # The README still says "Sensors required" → "supported" not present.
    # The README still says nothing about "robot" / "embodiment".
    assert not report.is_valid
    robot_errors = [
        i for i in report.errors if "robot" in i.field.lower() or "embodiment" in i.field.lower()
    ]
    assert robot_errors, f"expected a robots section error, got {report.errors}"


def test_readme_with_template_sentinel_blocks_publish(tmp_path: Path) -> None:
    readme = _GOOD_README + "\n\nUpload at hf://TEMPLATE_ORG/TEMPLATE_ID\n"
    skill_dir, manifest = _write_skill_dir(tmp_path, readme=readme)
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    placeholder_errors = [i for i in report.errors if i.field == "readme.placeholder"]
    assert placeholder_errors


def test_readme_with_todo_sentinel_blocks_publish(tmp_path: Path) -> None:
    readme = _GOOD_README + "\n\nTODO: write the architecture paragraph\n"
    skill_dir, manifest = _write_skill_dir(tmp_path, readme=readme)
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    assert any(i.field == "readme.placeholder" for i in report.errors)


# ── Manifest failure modes ───────────────────────────────────────────────────


def test_template_description_blocks_publish(tmp_path: Path) -> None:
    bad_yaml = _VALID_MANIFEST_YAML.replace(
        'description: "Picks a cube from the tabletop on the SO-100 follower arm."',
        (
            'description: "Scaffold template generated by ral skill new. '
            'Edit this description before publishing."'
        ),
    )
    skill_dir, manifest = _write_skill_dir(tmp_path, manifest_yaml=bad_yaml)
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    assert any(i.field == "manifest.description" for i in report.errors)


def test_every_placeholder_marker_in_description_is_caught(tmp_path: Path) -> None:
    """Each marker in :data:`PLACEHOLDER_MANIFEST_DESCRIPTION_MARKERS` is detected."""
    for marker in PLACEHOLDER_MANIFEST_DESCRIPTION_MARKERS:
        description = f"{marker} — example padding to clear the min-length bar."
        yaml_body = _VALID_MANIFEST_YAML.replace(
            'description: "Picks a cube from the tabletop on the SO-100 follower arm."',
            f'description: "{description}"',
        )
        # Use a unique subdir per iteration so file writes don't collide.
        sub = tmp_path / marker.replace(" ", "_").replace(":", "")
        sub.mkdir()
        skill_dir, manifest = _write_skill_dir(sub, manifest_yaml=yaml_body)
        report = validate_rskill_docs(skill_dir, manifest)
        assert not report.is_valid, f"marker {marker!r} should trigger a doc error"


def test_short_description_blocks_publish(tmp_path: Path) -> None:
    yaml_body = _VALID_MANIFEST_YAML.replace(
        'description: "Picks a cube from the tabletop on the SO-100 follower arm."',
        'description: "Picks a cube."',  # 13 chars, below MIN_DESCRIPTION_LENGTH=30
    )
    skill_dir, manifest = _write_skill_dir(tmp_path, manifest_yaml=yaml_body)
    report = validate_rskill_docs(skill_dir, manifest)
    assert not report.is_valid
    desc_errors = [i for i in report.errors if i.field == "manifest.description"]
    assert desc_errors


