# ── format_report ───────────────────────────────────────────────────────────


def test_format_report_valid_skill(tmp_path: Path) -> None:
    skill_dir, manifest = _write_skill_dir(tmp_path)
    report = validate_rskill_docs(skill_dir, manifest)
    rendered = format_report(report)
    assert "publish-ready" in rendered
    assert report.manifest_name in rendered


def test_format_report_invalid_skill(tmp_path: Path) -> None:
    skill_dir, manifest = _write_skill_dir(tmp_path, readme=None)
    report = validate_rskill_docs(skill_dir, manifest)
    rendered = format_report(report)
    assert "error:" in rendered
    assert "BLOCKED" in rendered


def test_format_report_isvalid_property(tmp_path: Path) -> None:
    skill_dir, manifest = _write_skill_dir(tmp_path)
    good_report = validate_rskill_docs(skill_dir, manifest)
    assert isinstance(good_report, DocValidationReport)
    assert good_report.is_valid is True
    assert good_report.errors == []

    bad_skill_dir, bad_manifest = _write_skill_dir(tmp_path / "broken", readme=None)
    bad_report = validate_rskill_docs(bad_skill_dir, bad_manifest)
    assert bad_report.is_valid is False
    assert len(bad_report.errors) >= 1


# ── Delegation ──────────────────────────────────────────────────────────────


def test_delegation_to_a_real_sibling_passes(tmp_path: Path) -> None:
    """A stub README that delegates to a sibling with all sections passes."""
    # Build the canonical sibling first.
    sibling_dir, sibling_manifest = _write_skill_dir(
        tmp_path / "canonical",
        manifest_yaml=_VALID_MANIFEST_YAML.replace(
            "test/rskill-doc-fixture", "test/rskill-canonical"
        ),
    )
    sibling_report = validate_rskill_docs(sibling_dir, sibling_manifest)
    assert sibling_report.is_valid

    # Now a stub that delegates.
    stub_dir = tmp_path / "stub" / "rskill-stub"
    stub_dir.mkdir(parents=True)
    (stub_dir / "rskill.yaml").write_text(
        _VALID_MANIFEST_YAML.replace("test/rskill-doc-fixture", "test/rskill-stub"),
        encoding="utf-8",
    )
    stub_readme = textwrap.dedent(f"""\
        # rskill-stub

        > A short variant that delegates to its canonical sibling.

        <!-- {DELEGATION_MARKER_NAME}: {sibling_dir} -->

        See the sibling README for shared architecture / license / sensors.

        Upstream: <https://huggingface.co/example/stub>
    """)
    (stub_dir / "README.md").write_text(stub_readme, encoding="utf-8")
    stub_manifest = RSkillManifest.from_yaml(str(stub_dir / "rskill.yaml"))
    report = validate_rskill_docs(stub_dir, stub_manifest)
    assert report.is_valid, report.errors


def test_delegation_to_missing_sibling_blocks_publish(tmp_path: Path) -> None:
    stub_dir, manifest = _write_skill_dir(
        tmp_path,
        readme=textwrap.dedent(f"""\
            # rskill-stub
            > Stub with a broken delegation marker.

            <!-- {DELEGATION_MARKER_NAME}: ./does-not-exist -->

            Upstream: <https://huggingface.co/example/stub>
        """),
    )
    report = validate_rskill_docs(stub_dir, manifest)
    assert not report.is_valid
    assert any(i.field == "readme.delegation" for i in report.errors)


def test_double_hop_delegation_is_rejected(tmp_path: Path) -> None:
    """A delegated-to README cannot itself delegate further."""
    # canonical → has full sections (so first hop "passes" sections)
    canonical_dir, _ = _write_skill_dir(
        tmp_path / "canonical",
        manifest_yaml=_VALID_MANIFEST_YAML.replace(
            "test/rskill-doc-fixture", "test/rskill-canonical"
        ),
    )

    # middle → delegates to canonical, but has the marker itself
    middle_dir = tmp_path / "middle" / "rskill-middle"
    middle_dir.mkdir(parents=True)
    middle_readme = textwrap.dedent(f"""\
        # rskill-middle
        > Middle stub.

        <!-- {DELEGATION_MARKER_NAME}: {canonical_dir} -->

        Padding text to clear the min-body length so the failure is
        the double-hop marker, not the short-body check.
        Upstream: <https://huggingface.co/example/middle>
    """)
    (middle_dir / "README.md").write_text(middle_readme, encoding="utf-8")
    (middle_dir / "rskill.yaml").write_text(
        _VALID_MANIFEST_YAML.replace("test/rskill-doc-fixture", "test/rskill-middle"),
        encoding="utf-8",
    )

    # top → delegates to middle (which itself delegates → should fail)
    top_dir = tmp_path / "top" / "rskill-top"
    top_dir.mkdir(parents=True)
    top_readme = textwrap.dedent(f"""\
        # rskill-top
        > Top of the chain.

        <!-- {DELEGATION_MARKER_NAME}: {middle_dir} -->

        Padding text to clear the min-body length so the failure is the
        double-hop marker, not the short-body check.
        Upstream: <https://huggingface.co/example/top>
    """)
    (top_dir / "README.md").write_text(top_readme, encoding="utf-8")
    (top_dir / "rskill.yaml").write_text(
        _VALID_MANIFEST_YAML.replace("test/rskill-doc-fixture", "test/rskill-top"),
        encoding="utf-8",
    )

    manifest = RSkillManifest.from_yaml(str(top_dir / "rskill.yaml"))
    report = validate_rskill_docs(top_dir, manifest)
    assert not report.is_valid
    delegation_errors = [i for i in report.errors if i.field == "readme.delegation"]
    assert delegation_errors


def test_delegation_still_enforces_placeholder_check(tmp_path: Path) -> None:
    """A delegating stub README must not contain template sentinels itself."""
    canonical_dir, _ = _write_skill_dir(
        tmp_path / "canonical",
        manifest_yaml=_VALID_MANIFEST_YAML.replace(
            "test/rskill-doc-fixture", "test/rskill-canonical"
        ),
    )
    stub_dir = tmp_path / "stub" / "rskill-stub"
    stub_dir.mkdir(parents=True)
    (stub_dir / "rskill.yaml").write_text(
        _VALID_MANIFEST_YAML.replace("test/rskill-doc-fixture", "test/rskill-stub"),
        encoding="utf-8",
    )
    # Stub README delegates but also still contains a TODO: sentinel.
    stub_readme = textwrap.dedent(f"""\
        # rskill-stub
        > A stub that still has a TODO inside.

        <!-- {DELEGATION_MARKER_NAME}: {canonical_dir} -->

        TODO: write the action / state contract before publish.

        Upstream: <https://huggingface.co/example/stub>
    """)
    (stub_dir / "README.md").write_text(stub_readme, encoding="utf-8")
    manifest = RSkillManifest.from_yaml(str(stub_dir / "rskill.yaml"))
    report = validate_rskill_docs(stub_dir, manifest)
    assert not report.is_valid
    placeholders = [i for i in report.errors if i.field == "readme.placeholder"]
    assert placeholders


# ── Template scaffold fails publish-readiness ────────────────────────────────


def test_template_scaffold_fails_publish_readiness() -> None:
    """The bare ``rskills/template/`` scaffold MUST fail the publish gate.

    Catches the regression where the template's docs accidentally start
    looking like a real, ready-to-publish rSkill — that would let a
    user run ``python tools/rskill_publisher.py rskills/template/
    --publish`` and upload a placeholder package.
    """
    repo_root = Path(__file__).resolve().parents[2]
    template_dir = repo_root / "rskills" / "template"
    manifest = RSkillManifest.from_yaml(str(template_dir / "rskill.yaml"))
    report = validate_rskill_docs(template_dir, manifest)
    assert not report.is_valid, (
        "The template scaffold MUST fail the publish gate; if it just started "
        "passing, the placeholder sentinels were probably stripped from "
        "rskills/template/README.md or rskill.yaml — re-add them."
    )


# ── In-tree regression guard ────────────────────────────────────────────────


def _intree_skill_dirs() -> list[Path]:
    """Return every ``rskills/<id>/`` dir except the scaffold template."""
    repo_root = Path(__file__).resolve().parents[2]
    rskills_dir = repo_root / "rskills"
    out: list[Path] = []
    for child in sorted(rskills_dir.iterdir()):
        if not child.is_dir():
            continue
        if child.name == "template":
            continue
        if not (child / "rskill.yaml").is_file():
            continue
        out.append(child)
    return out


@pytest.mark.parametrize("skill_dir", _intree_skill_dirs(), ids=lambda p: p.name)
def test_every_intree_rskill_passes_publish_readiness(skill_dir: Path) -> None:
    """Regression guard: every shipped rSkill is publish-ready.

    If this fails after a refactor of the validator, either the
    validator tightened beyond the in-tree skills (update them) or an
    in-tree skill regressed (update the skill).
    """
    manifest = RSkillManifest.from_yaml(str(skill_dir / "rskill.yaml"))
    report = validate_rskill_docs(skill_dir, manifest)
    if not report.is_valid:
        rendered = "\n".join(f"  - [{i.field}] {i.message}" for i in report.errors)
        pytest.fail(f"in-tree rSkill {skill_dir.name} is not publish-ready:\n{rendered}")
